<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; class Service extends Model { protected $fillable = ['category_id', 'name', 'description', 'base_price', 'reseller_price', 'min_quantity', 'max_quantity', 'refill_days', 'is_active', 'provider', 'provider_data']; protected $casts = ['provider_data' => 'array']; public function category() { return $this->belongsTo(Category::class); } public function orders() { return $this->hasMany(Order::class); } }